var e=JSON.parse(`[{"id":"L1_1","type":"subtitle","speaker":null,"text":{"KOREA":"<color=#ffd34c>심도 3등급</color>     \\n이터니움 채굴구역     ","JPN":"<color=#ffd34c>深度レベル3</color>     \\nエタニウム採掘区域     ","ENG":"[[","TWN":"<color=#ffd34c>深度 3等級</color>     \\n永恆之金採集區域","THA":"<color=#ffd34c>ความลึกระดับ 3</color>     \\nพื้นที่ทำเหมืองอีเทอร์เนียม     ","VTN":"<color=#ffd34c>Độ Sâu 3</color>     \\nKhu Vực Khai Mỏ Vàng Vĩnh Cửu     ","SCN":"<color=#ffd34c>深度 3等级</color>     \\n能晶采集区域     ","DEU":"[[","FRA":"<color=#ffd34c>Profondeur\xA03</color>     \\nMine d'éternium     "},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"망할 업주 놈들. 뭐가 자기들이 손해 보는 장사라는 거야.","JPN":"クソ業者どもめ。やっぱり損するのは俺たちじゃないか。","ENG":"Damn those business owners. How can they be losing any money from this?","TWN":"一群該死的雇主，什麼叫他們在做虧本生意啊。"},"stage":{"bg":"COUNTERSIDE_PLAIN","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"고작 이런 인원만 불러다 놓고 침식체들을 막으라니......","JPN":"この人数で侵食体を防げるはずないだろ……","ENG":"They want us to fend off the C.O. with just this many people?","TWN":"竟然只叫了幾個人，就想阻止侵蝕體……"},"stage":{"bg":"COUNTERSIDE_PLAIN","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"탄약 값은 기본 옵션인 줄 아는 건가?","JPN":"弾薬だってタダじゃないんだ。","ENG":"Do they think we all come attached with ammo?","TWN":"他們知道什麼是內定選項嗎？"},"stage":{"bg":"COUNTERSIDE_PLAIN","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"EDDIE_RSEVEN_NULL_NULL","text":{"KOREA":"계약을 할 땐 원래 정직한 쪽이 손해보는 법이지.","JPN":"契約はいつも正直なヤツが損するものだ。","ENG":"It's the honest party that always loses when signing a contract.","TWN":"簽約的時候，本來就是老實人吃虧。"},"stage":{"bg":"COUNTERSIDE_PLAIN","slots":{"L":null,"C":null,"R":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"EDDIE_RSEVEN_NULL_NULL","text":{"KOREA":"손해보기 싫으면 자기 몸값에 거품을 깔아두는 편이 좋아.","JPN":"損をしたくないなら、契約の時は大きく出た方がいい。","ENG":"If you don't want to lose anything, you should exaggerate your pay.","TWN":"如果你不想吃虧的話，那最好幫自己的身價灌個水。"},"stage":{"bg":"COUNTERSIDE_PLAIN","slots":{"L":null,"C":null,"R":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"EDDIE_RSEVEN_NULL_NULL","text":{"KOREA":"시작부터 본전치기로 부르면 무조건 협상이 불리해지거든.","JPN":"正直な態度は交渉に不利だ。どうせ報酬は値引きされるんだからな。","ENG":"If you start off your deal to break even, you've already lost the deal.","TWN":"不然你一開始就說出底價的話，那談判就會無條件地以不利收場。"},"stage":{"bg":"COUNTERSIDE_PLAIN","slots":{"L":null,"C":null,"R":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"쳇, 난 일을 하러 온 거지, 장사를 배우러 온 게 아니라고.","JPN":"チッ、俺は商売じゃなくて仕事をしに来たんだ。","ENG":"Tsk, I'm here to work, not to conduct business.","TWN":"切，我是來工作，不是來學做生意的。"},"stage":{"bg":"COUNTERSIDE_PLAIN","slots":{"L":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"EDDIE_RSEVEN_NULL_NULL","text":{"KOREA":"뭐, 따지고 보면 이것도 마냥 손해 보는 임무는 아냐.","JPN":"まあ、この任務も損ばかりじゃない。","ENG":"Well honestly, this mission isn't that bad.","TWN":"算了吧。仔細想想，這也不完全是個虧本任務。"},"stage":{"bg":"COUNTERSIDE_PLAIN","slots":{"L":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L25_1","type":"dialog","speaker":"EDDIE_RSEVEN_NULL_NULL","text":{"KOREA":"우리가 맡은 임무는 채굴지를 방어하는 거다.","JPN":"俺たちの任務は採掘地の防衛だ。","ENG":"Our mission is to defend the mining site.","TWN":"我們負責的任務是保護採掘場。"},"stage":{"bg":"COUNTERSIDE_PLAIN","slots":{"L":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"EDDIE_RSEVEN_NULL_NULL","text":{"KOREA":"그 말인 즉, 침식체들 몸에 박힌 이터니움은 계약에 포함되지 않는 우리 몫이란 뜻이지.","JPN":"つまり、侵食体の体に埋まってるエタニウムは契約に含まれないから、俺たちの好きにしていいってことだ。","ENG":"Which means the Eternium embedded in C.O. are not included in the contract. They're all ours.","TWN":"也就是說，侵蝕體體內的永恆之金不在契約範圍內，那就是我們的份了。"},"stage":{"bg":"COUNTERSIDE_PLAIN","slots":{"L":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"......당신은 누구지? 그런 정보를 굳이 나한테 줘서 득 될 거라도 있나?","JPN":"……あんた何なんだ？俺に情報を与えて、あんたに何の得がある？","ENG":"And who might you be? Do you get anything out of telling me this information?","TWN":"……你是誰啊？特別告訴我這個情報，是能得到什麼好處嗎？"},"stage":{"bg":"COUNTERSIDE_PLAIN","slots":{"L":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"EDDIE_RSEVEN_NULL_NULL","text":{"KOREA":"이봐, 침식체의 이터니움을 추출을 하는 것도 집중이 필요한 작업이라고.","JPN":"侵食体からエタニウムを抽出するには、慎重に作業しなければならない。","ENG":"Look, extracting Eternium from C.O. requires a lot of concentration.","TWN":"因為你看，提取侵蝕體體內的永恆之金，是個需要集中精神的作業。"},"stage":{"bg":"COUNTERSIDE_PLAIN","slots":{"L":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"EDDIE_RSEVEN_NULL_NULL","text":{"KOREA":"내가 작업을 하는 동안 뒤를 맡길 수 있는 협력자 정도는 있어야지 않겠어?","JPN":"だから作業をする間、俺を守ってくれるやつが必要だ。","ENG":"I could use an ally to watch my back while I work my magic.","TWN":"我在幹活的時候，總得把背後交給某個幫手吧？"},"stage":{"bg":"COUNTERSIDE_PLAIN","slots":{"L":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"8대 2.","JPN":"8対2。","ENG":"80-20.","TWN":"8比2"},"stage":{"bg":"COUNTERSIDE_PLAIN","slots":{"L":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"EDDIE_RSEVEN_NULL_NULL","text":{"KOREA":"......장비가 첨단이라서 몰라 뵀는데, 수완은 영 초짜인 친구일세.","JPN":"……最新装備で身を固めてたから気づかなかったが、完全に素人だな。","ENG":"I had no idea you were such a novice with all your fancy tech gear.","TWN":"……一開始因為你的裝備都很高科技，所以沒看出來，但你真的是隻菜雞呢。"},"stage":{"bg":"COUNTERSIDE_PLAIN","slots":{"L":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EDDIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};